const svg = $('#w1-svg'), out = $('#w1-out');
const slider = $('#w1-j');
const buttons = $$('#w-jslider button[data-j]');

// pick (a,b) for given j via the standard family y^2 = x^3 - 3kx - 2k (k = j/(j-1728))
// when j != 0, 1728: take k = j/(1728 - j), a = -3k, b = -2k.
function ab(j){
  if(Math.abs(j) < 1e-6) return [0, 1];       // y^2 = x^3 + 1
  if(Math.abs(j - 1728) < 1e-6) return [1, 0]; // y^2 = x^3 + x
  const k = j / (1728 - j);
  return [-3*k, -2*k];
}

function draw(){
  svg.innerHTML = '';
  const j = +slider.value;
  const [a,b] = ab(j);

  // axes box
  const X0=60, Y0=30, W=500, H=260;
  svg.appendChild(SVG('rect',{x:X0,y:Y0,width:W,height:H,fill:'var(--panel2)',stroke:'var(--line)'}));

  // draw curve y^2 = x^3 + a x + b over x ∈ [xmin, xmax]
  // rescale so the interesting region fits. Use a fixed x-range [-3, 3] scaled to box.
  const xmin=-3, xmax=3, ymin=-4, ymax=4;
  const toPx = (x,y) => [X0 + (x-xmin)/(xmax-xmin)*W, Y0 + H - (y-ymin)/(ymax-ymin)*H];

  // axes
  const [ax0,ay0] = toPx(0,ymin), [ax1,ay1] = toPx(0,ymax);
  svg.appendChild(SVG('line',{x1:ax0,y1:ay0,x2:ax1,y2:ay1,stroke:'var(--line)','stroke-width':1}));
  const [bx0,by0] = toPx(xmin,0), [bx1,by1] = toPx(xmax,0);
  svg.appendChild(SVG('line',{x1:bx0,y1:by0,x2:bx1,y2:by1,stroke:'var(--line)','stroke-width':1}));

  // plot curve: for each x, if x^3 + ax + b >= 0, draw (x, ±sqrt). walk in x.
  // We produce two polylines: upper and lower branches, possibly disconnected.
  function sample(sign){
    const pts=[]; let current=[];
    const N=600;
    for(let i=0;i<=N;i++){
      const x = xmin + (xmax-xmin)*i/N;
      const v = x*x*x + a*x + b;
      if(v < 0){
        if(current.length>1) pts.push(current);
        current=[];
        continue;
      }
      const y = sign*Math.sqrt(v);
      if(y<ymin || y>ymax){
        if(current.length>1) pts.push(current);
        current=[];
        continue;
      }
      current.push(toPx(x,y));
    }
    if(current.length>1) pts.push(current);
    return pts;
  }
  const color = 'var(--yellow)';
  const allPts = [...sample(+1), ...sample(-1)];
  for(const arr of allPts){
    const d = 'M' + arr.map(p=>p[0].toFixed(1)+','+p[1].toFixed(1)).join(' L');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:color,'stroke-width':2}));
  }

  // equation label
  const eq = SVG('text',{x:X0+10,y:Y0+22,'font-size':14,fill:'var(--mute)'});
  eq.textContent = `y² = x³ + (${a.toFixed(3)}) x + (${b.toFixed(3)})`;
  svg.appendChild(eq);

  // readout
  const disc = -16*(4*a*a*a + 27*b*b);
  out.textContent = `j = ${j.toFixed(1)}   (a, b) = (${a.toFixed(3)}, ${b.toFixed(3)})   Δ = ${disc.toFixed(2)}`;
}
slider.addEventListener('input', draw);
buttons.forEach(b => b.addEventListener('click', () => { slider.value = b.dataset.j; draw(); }));
draw();

const svg = $('#w2-svg'), out = $('#w2-out');
const btns = $$('.w2-btn');
const anim = $('#w2-animate');
let mode = 'generic';
let t = 0, running = false, raf = null;

const DATA = {
  generic: {a:-1, b:1, j:'≈ 1259', aut:'Z/2', desc:'generic curve y² = x³ - x + 1. Only non-trivial aut: (x,y) ↦ (x, -y).'},
  j0:      {a:0,  b:1, j:'0',       aut:'Z/6', desc:'j = 0: y² = x³ + 1. Aut = Z/6 generated by (x,y) ↦ (ω x, -y), ω = e^{2πi/3}.'},
  j1728:   {a:1,  b:0, j:'1728',    aut:'Z/4', desc:'j = 1728: y² = x³ + x. Aut = Z/4 generated by (x,y) ↦ (-x, i y).'}
};

function draw(){
  svg.innerHTML = '';
  const D = DATA[mode];
  const X0=60, Y0=30, W=500, H=260;
  svg.appendChild(SVG('rect',{x:X0,y:Y0,width:W,height:H,fill:'var(--panel2)',stroke:'var(--line)'}));
  const xmin=-2.5, xmax=2.5, ymin=-3, ymax=3;
  const toPx = (x,y)=>[X0 + (x-xmin)/(xmax-xmin)*W, Y0 + H - (y-ymin)/(ymax-ymin)*H];

  const [ax0,ay0] = toPx(0,ymin), [ax1,ay1] = toPx(0,ymax);
  svg.appendChild(SVG('line',{x1:ax0,y1:ay0,x2:ax1,y2:ay1,stroke:'var(--line)'}));
  const [bx0,by0] = toPx(xmin,0), [bx1,by1] = toPx(xmax,0);
  svg.appendChild(SVG('line',{x1:bx0,y1:by0,x2:bx1,y2:by1,stroke:'var(--line)'}));

  // draw real locus
  const {a,b} = D;
  function samp(sign){
    const N=600, out=[]; let cur=[];
    for(let i=0;i<=N;i++){
      const x=xmin+(xmax-xmin)*i/N;
      const v=x*x*x + a*x + b;
      if(v<0){ if(cur.length>1) out.push(cur); cur=[]; continue; }
      const y=sign*Math.sqrt(v);
      if(y<ymin||y>ymax){ if(cur.length>1) out.push(cur); cur=[]; continue; }
      cur.push(toPx(x,y));
    }
    if(cur.length>1) out.push(cur);
    return out;
  }
  const all = [...samp(+1), ...samp(-1)];
  for(const arr of all){
    const d='M'+arr.map(p=>p[0].toFixed(1)+','+p[1].toFixed(1)).join(' L');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--yellow)','stroke-width':2}));
  }

  // sample tracking point, apply the automorphism angle t
  // For Z/2: (x,y) → (x, -y). Linear interp on y.
  // For Z/4 (j=1728): rotate by 90°· t on (x, y) → (-x, iy) complex; we simulate by rotating the DISPLAYED
  //   representative: (x, y) in plane gets rotated: x -> x·cos(πt/2) - y·sin(πt/2) ? No: we want to show a 4-fold symmetry.
  // For demo, draw a ghost (rotated by the group action). We'll just mark the aut by rotating a marker point
  // by the group action around the origin (as a geometric avatar only).
  const order = mode==='generic'?2: mode==='j1728'?4: 6;
  const angle = (2*Math.PI/order) * t;
  const mx = 1.3, my = Math.sqrt(Math.max(0, mx*mx*mx + a*mx + b));
  // rotate (mx,my) by angle (avatar rotation only)
  const rx = mx*Math.cos(angle) - my*Math.sin(angle);
  const ry = mx*Math.sin(angle) + my*Math.cos(angle);
  const [px,py] = toPx(rx, ry);
  svg.appendChild(SVG('circle',{cx:px,cy:py,r:6,fill:'var(--pink)'}));
  const [ox,oy] = toPx(mx,my);
  svg.appendChild(SVG('circle',{cx:ox,cy:oy,r:4,fill:'var(--blue)','fill-opacity':0.5}));

  const lab = SVG('text',{x:X0+10,y:Y0+22,'font-size':14,fill:'var(--mute)'});
  lab.textContent = `mode: ${mode}   j = ${D.j}   Aut = ${D.aut}`;
  svg.appendChild(lab);
  const hint = SVG('text',{x:X0+W-10,y:Y0+22,'font-size':12,fill:'var(--mute)','text-anchor':'end'});
  hint.textContent = `order of Aut: ${order}`;
  svg.appendChild(hint);

  out.textContent = D.desc;
}

function step(){
  if(!running) return;
  t = (t + 0.01) % 1;
  draw();
  raf = requestAnimationFrame(step);
}

btns.forEach(b => b.addEventListener('click', () => {
  btns.forEach(x => x.classList.remove('active'));
  b.classList.add('active');
  mode = b.dataset.mode;
  t = 0;
  draw();
}));
anim.addEventListener('click', () => {
  running = !running;
  anim.textContent = running ? 'stop animation' : 'animate automorphism';
  if(running){ step(); } else { cancelAnimationFrame(raf); }
});

draw();

const svg = $('#w3-svg'), out = $('#w3-out');
const btns = $$('.w3-btn');
let mode = 'fine';

function draw(){
  svg.innerHTML = '';
  const W=620, H=300;
  // nodes: S (top-left), M (bottom-left), E_over_S (top-right), E_over_M (bottom-right)
  const S = [130, 80], M = [130, 220], EoverS = [420, 80], EoverM = [420, 220];

  // arrows
  drawArrow(svg, S, M, {label:'classifying map', color:'var(--blue)', markerId:'w3-blue'});
  drawArrow(svg, EoverS, S, {label:'family', color:'var(--yellow)', markerId:'w3-ye'});
  drawArrow(svg, EoverM, M, {label:mode==='fine'?'universal family':'no univ. family', color: mode==='fine'?'var(--green)':'var(--pink)', markerId:mode==='fine'?'w3-gr':'w3-pn', dash: mode==='fine'? null:'6 5'});
  // pullback arrow from EoverS -> EoverM
  drawArrow(svg, EoverS, EoverM, {label:'pullback', color:'var(--cyan)', markerId:'w3-cy'});

  drawNode(svg, S[0], S[1], 'S', {r:24, stroke:'var(--blue)'});
  drawNode(svg, M[0], M[1], 'M', {r:24, stroke:'var(--violet)'});
  drawNode(svg, EoverS[0], EoverS[1], 'E/S', {r:26, stroke:'var(--yellow)'});
  drawNode(svg, EoverM[0], EoverM[1], 'ℰ/M', {r:26, stroke: mode==='fine'?'var(--green)':'var(--pink)'});

  // caption
  const cap = SVG('text',{x:W/2,y:H-15,'text-anchor':'middle','font-size':14,fill:'var(--mute)'});
  cap.textContent = mode==='fine'
    ? 'fine: every family E/S is uniquely the pullback of the universal family ℰ/M along S → M'
    : 'coarse: S → M exists pointwise via j-invariant, but NO universal family ℰ/M exists';
  svg.appendChild(cap);

  out.textContent = mode==='fine'
    ? 'fine moduli: ℳ(S) ≅ Hom(S,M) naturally. Universal family ℰ → M classifies everything.'
    : 'coarse moduli: ℳ(Spec k̄) ↔ M(k̄) bijectively, but no universal family exists. (This is the j-line situation.)';
}

btns.forEach(b => b.addEventListener('click', () => {
  btns.forEach(x => x.classList.remove('active'));
  b.classList.add('active');
  mode = b.dataset.mode;
  draw();
}));

draw();

const svg = $('#w4-svg'), out = $('#w4-out');
const slider = $('#w4-t');

function curvePath(a, b, xmin, xmax, ymin, ymax, toPx){
  function samp(sign){
    const N=400, out=[]; let cur=[];
    for(let i=0;i<=N;i++){
      const x=xmin+(xmax-xmin)*i/N;
      const v=x*x*x + a*x + b;
      if(v<0){ if(cur.length>1) out.push(cur); cur=[]; continue; }
      const y=sign*Math.sqrt(v);
      if(y<ymin||y>ymax){ if(cur.length>1) out.push(cur); cur=[]; continue; }
      cur.push(toPx(x,y));
    }
    if(cur.length>1) out.push(cur);
    return out;
  }
  return [...samp(+1), ...samp(-1)];
}

function drawPanel(X0, Y0, W, H, a, b, title, color){
  svg.appendChild(SVG('rect',{x:X0,y:Y0,width:W,height:H,fill:'var(--panel2)',stroke:'var(--line)'}));
  const xmin=-3.5, xmax=3.5, ymin=-5, ymax=5;
  const toPx=(x,y)=>[X0 + (x-xmin)/(xmax-xmin)*W, Y0 + H - (y-ymin)/(ymax-ymin)*H];

  const [ax0,ay0] = toPx(0,ymin), [ax1,ay1] = toPx(0,ymax);
  svg.appendChild(SVG('line',{x1:ax0,y1:ay0,x2:ax1,y2:ay1,stroke:'var(--line)'}));
  const [bx0,by0] = toPx(xmin,0), [bx1,by1] = toPx(xmax,0);
  svg.appendChild(SVG('line',{x1:bx0,y1:by0,x2:bx1,y2:by1,stroke:'var(--line)'}));

  const pts = curvePath(a, b, xmin, xmax, ymin, ymax, toPx);
  for(const arr of pts){
    const d='M'+arr.map(p=>p[0].toFixed(1)+','+p[1].toFixed(1)).join(' L');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:color,'stroke-width':2}));
  }
  const lab = SVG('text',{x:X0 + W/2, y:Y0+18, 'text-anchor':'middle','font-size':13,fill:'var(--ink)'});
  lab.textContent = title;
  svg.appendChild(lab);
}

function draw(){
  svg.innerHTML = '';
  const t = +slider.value;
  // E1: a=0, b=1 (always)
  // E2: a=0, b=t^6 — fibre at this t, so coefficient is t^6
  const b2 = Math.pow(t, 6);
  drawPanel(20, 20, 280, 260, 0, 1, 'E₁: y² = x³ + 1 (fibre at t)', 'var(--yellow)');
  drawPanel(320, 20, 280, 260, 0, b2, `E₂: y² = x³ + t⁶ = x³ + ${b2.toFixed(3)}`, 'var(--cyan)');

  // connecting label
  const cap = SVG('text',{x:310, y:305,'text-anchor':'middle','font-size':12,fill:'var(--pink)','font-style':'italic'});
  cap.textContent = `iso at t: (x,y) ↦ (t²x, t³y).   requires t ≠ 0.`;
  svg.appendChild(cap);

  out.textContent = `t = ${t.toFixed(3)}   E₂ coeff = t⁶ = ${b2.toFixed(4)}.   At every t ≠ 0 fibres are iso; not iso as families over A¹\\{0}.`;
}

slider.addEventListener('input', draw);
draw();

const svg = $('#w5-svg'), out = $('#w5-out');
const labelBtn = $('#w5-label'), swapBtn = $('#w5-swap');
let showLabels = true;
let swap = false;

// fix curve y^2 = x^3 - x (so j = 1728). Then 2-torsion points over C:
// y = 0 → x^3 - x = 0 → x ∈ {0, 1, -1}. Plus the point at infinity O.
// In the real plane: (0,0), (1,0), (-1,0), plus "O" drawn off-box.
function draw(){
  svg.innerHTML = '';
  const X0=60, Y0=30, W=500, H=260;
  svg.appendChild(SVG('rect',{x:X0,y:Y0,width:W,height:H,fill:'var(--panel2)',stroke:'var(--line)'}));
  const xmin=-2, xmax=2, ymin=-2.5, ymax=2.5;
  const toPx=(x,y)=>[X0 + (x-xmin)/(xmax-xmin)*W, Y0 + H - (y-ymin)/(ymax-ymin)*H];

  const [ax0,ay0] = toPx(0,ymin), [ax1,ay1] = toPx(0,ymax);
  svg.appendChild(SVG('line',{x1:ax0,y1:ay0,x2:ax1,y2:ay1,stroke:'var(--line)'}));
  const [bx0,by0] = toPx(xmin,0), [bx1,by1] = toPx(xmax,0);
  svg.appendChild(SVG('line',{x1:bx0,y1:by0,x2:bx1,y2:by1,stroke:'var(--line)'}));

  // curve y² = x³ - x, real locus: two components
  const a=-1, b=0;
  function samp(sign){
    const N=500,out=[]; let cur=[];
    for(let i=0;i<=N;i++){
      const x=xmin+(xmax-xmin)*i/N;
      const v=x*x*x + a*x + b;
      if(v<0){ if(cur.length>1) out.push(cur); cur=[]; continue; }
      const y=sign*Math.sqrt(v);
      if(y<ymin||y>ymax){ if(cur.length>1) out.push(cur); cur=[]; continue; }
      cur.push(toPx(x,y));
    }
    if(cur.length>1) out.push(cur);
    return out;
  }
  const all=[...samp(+1),...samp(-1)];
  for(const arr of all){
    const d='M'+arr.map(p=>p[0].toFixed(1)+','+p[1].toFixed(1)).join(' L');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--yellow)','stroke-width':2}));
  }

  // 2-torsion points
  // O is "at infinity", we'll just draw a marker near the top-right with label
  // non-trivial: P1 = (-1,0), P2 = (0,0), P3 = (1,0). Under swap, swap labels of P1 and P2.
  const basePts = [
    {name: swap?'P2':'P1', x:-1, y:0, color:'var(--pink)'},
    {name: swap?'P1':'P2', x: 0, y:0, color:'var(--cyan)'},
    {name: 'P3',            x: 1, y:0, color:'var(--green)'},
  ];
  for(const p of basePts){
    const [px,py] = toPx(p.x, p.y);
    svg.appendChild(SVG('circle',{cx:px,cy:py,r:6,fill:p.color}));
    if(showLabels){
      const t = SVG('text',{x:px,y:py-12,'text-anchor':'middle','font-size':12,fill:p.color,'font-weight':600});
      t.textContent = p.name;
      svg.appendChild(t);
    }
  }
  // label O
  const [ox,oy] = [X0 + W - 50, Y0 + 50];
  svg.appendChild(SVG('circle',{cx:ox,cy:oy,r:6,fill:'var(--violet)'}));
  if(showLabels){
    const t = SVG('text',{x:ox,y:oy-12,'text-anchor':'middle','font-size':12,fill:'var(--violet)','font-weight':600});
    t.textContent = 'O (∞)';
    svg.appendChild(t);
  }

  const lab = SVG('text',{x:X0+10,y:Y0+22,'font-size':13,fill:'var(--mute)'});
  lab.textContent = `y² = x³ - x   (j = 1728).   E[2] = {O, (-1,0), (0,0), (1,0)}.`;
  svg.appendChild(lab);

  out.textContent = swap
    ? 'automorphism applied: labels P1 ↔ P2 have swapped. A level-2 structure (choice of ordered basis) is NOT fixed — but note [-1] acts trivially on E[2]. So level-2 is not rigid enough; N ≥ 3 needed.'
    : 'unlabelled 2-torsion: {O, (-1,0), (0,0), (1,0)}. [-1]: (x,y)↦(x,-y) fixes all of them pointwise. Automorphisms of the curve permute {P1,P2,P3}.';
}

labelBtn.addEventListener('click', () => { showLabels = !showLabels; draw(); });
swapBtn.addEventListener('click', () => { swap = !swap; draw(); });
draw();

const svg = $('#w6-svg'), out = $('#w6-out');
const row = $('#w6-buttons');

const GALLERY = [
  {key:'g0', g:0, n:3, stable:true, title:'(g,n) = (0,3) · P¹ with 3 marked points',
   desc:'dim M₀,₃ = 0 — a single point. Stable because 3 marked points satisfy the rule for rational components.'},
  {key:'g1', g:1, n:1, stable:true, title:'(g,n) = (1,1) · smooth elliptic curve, 1 marked point',
   desc:'dim M₁,₁ = 1. This is the j-line. Smooth genus-1 with one marking (the origin).'},
  {key:'g2', g:2, n:0, stable:true, title:'(g,n) = (2,0) · smooth genus-2 curve',
   desc:'dim M₂ = 3g - 3 = 3. A hyperelliptic surface with six Weierstrass points.'},
  {key:'g3', g:3, n:0, stable:true, title:'(g,n) = (3,0) · smooth genus-3 curve',
   desc:'dim M₃ = 6. Generic g=3 curve is a smooth plane quartic.'},
  {key:'g4', g:4, n:0, stable:true, title:'(g,n) = (4,0) · smooth genus-4 curve',
   desc:'dim M₄ = 9. Generic g=4 curve is a complete intersection of quadric + cubic in P³.'},
  {key:'g2n1', g:2, n:0, stable:true, title:'(g,n) = (2,0) · nodal: two elliptic curves glued at a point',
   desc:'Stable degeneration in ∂M̄₂: two genus-1 components meeting at a node. Arithmetic genus = 1+1+0 = 2. ✓ stable: each genus-1 component has 1 special point (the node).'},
  {key:'g2n2', g:2, n:0, stable:true, title:'(g,n) = (2,0) · irreducible self-node',
   desc:'Geometric genus 1, arithmetic genus 2 via the self-node. Smoothing parameter gives a local chart of M̄₂ near the boundary.'},
  {key:'g0n5', g:0, n:5, stable:true, title:'(g,n) = (0,5) · P¹ with 5 marked points',
   desc:'dim M₀,₅ = 2. The boundary ∂M̄₀,₅ is a union of divisors, one for each way to split {1..5} into two groups of size ≥ 2.'},
];

let idx = 1;

function drawCurve(key){
  // draw a schematic "curve" in the middle of the SVG
  const W=620, H=340;
  svg.innerHTML = '';
  svg.appendChild(SVG('rect',{x:20,y:20,width:W-40,height:H-40,fill:'var(--panel2)',stroke:'var(--line)'}));

  // For each key, hand-crafted cartoon
  function genus0(cx,cy){
    // a horizontal line with 3 or 5 dots
    svg.appendChild(SVG('line',{x1:cx-140,y1:cy,x2:cx+140,y2:cy,stroke:'var(--yellow)','stroke-width':2}));
    return {cx,cy};
  }
  function genusHandles(cx,cy,n){
    // draw a tube with n handles (figure of genus n via n circles stacked horizontally, connected)
    // For simplicity just draw n circles joined.
    const spacing = 70;
    const x0 = cx - (n-1)*spacing/2;
    for(let i=0;i<n;i++){
      svg.appendChild(SVG('ellipse',{cx:x0+i*spacing,cy:cy,rx:35,ry:24,fill:'none',stroke:'var(--yellow)','stroke-width':2}));
    }
    // connect them with a bold envelope
    const env = SVG('ellipse',{cx:cx,cy:cy,rx:(n-1)*spacing/2+50,ry:36,fill:'none',stroke:'var(--yellow)','stroke-width':1.5,'stroke-dasharray':'3 3'});
    svg.appendChild(env);
  }
  function markDots(cx, cy, count, yOffset=0){
    for(let i=0;i<count;i++){
      const x = cx - (count-1)*20 + i*40;
      svg.appendChild(SVG('circle',{cx:x,cy:cy+yOffset,r:5,fill:'var(--pink)',stroke:'#fff','stroke-width':1}));
      const t = SVG('text',{x:x,y:cy+yOffset-12,'text-anchor':'middle','font-size':11,fill:'var(--pink)'});
      t.textContent = 'p'+(i+1);
      svg.appendChild(t);
    }
  }

  const cx=W/2, cy=H/2-10;
  if(key==='g0'){ genus0(cx,cy); markDots(cx,cy,3,-10); }
  else if(key==='g1'){ genusHandles(cx,cy,1); markDots(cx,cy-40,1); }
  else if(key==='g2'){ genusHandles(cx,cy,2); }
  else if(key==='g3'){ genusHandles(cx,cy,3); }
  else if(key==='g4'){ genusHandles(cx,cy,4); }
  else if(key==='g2n1'){
    // two ellipses meeting at a central node
    svg.appendChild(SVG('ellipse',{cx:cx-70,cy:cy,rx:55,ry:35,fill:'none',stroke:'var(--yellow)','stroke-width':2}));
    svg.appendChild(SVG('ellipse',{cx:cx+70,cy:cy,rx:55,ry:35,fill:'none',stroke:'var(--cyan)','stroke-width':2}));
