const DATA = {
  generic: {a:-1, b:1, j:'≈ 1259', aut:'Z/2', desc:'generic curve y² = x³ - x + 1. Only non-trivial aut: (x,y) ↦ (x, -y).'},
  j0:      {a:0,  b:1, j:'0',       aut:'Z/6', desc:'j = 0: y² = x³ + 1. Aut = Z/6 generated by (x,y) ↦ (ω x, -y), ω = e^{2πi/3}.'},
  j1728:   {a:1,  b:0, j:'1728',    aut:'Z/4', desc:'j = 1728: y² = x³ + x. Aut = Z/4 generated by (x,y) ↦ (-x, i y).'}
};

function draw(){
  svg.innerHTML = '';
  const D = DATA[mode];
  const X0=60, Y0=30, W=500, H=260;
  svg.appendChild(SVG('rect',{x:X0,y:Y0,width:W,height:H,fill:'var(--panel2)',stroke:'var(--line)'}));
  const xmin=-2.5, xmax=2.5, ymin=-3, ymax=3;
  const toPx = (x,y)=>[X0 + (x-xmin)/(xmax-xmin)*W, Y0 + H - (y-ymin)/(ymax-ymin)*H];

  const [ax0,ay0] = toPx(0,ymin), [ax1,ay1] = toPx(0,ymax);
  svg.appendChild(SVG('line',{x1:ax0,y1:ay0,x2:ax1,y2:ay1,stroke:'var(--line)'}));
  const [bx0,by0] = toPx(xmin,0), [bx1,by1] = toPx(xmax,0);
  svg.appendChild(SVG('line',{x1:bx0,y1:by0,x2:bx1,y2:by1,stroke:'var(--line)'}));

  // draw real locus
  const {a,b} = D;
  function samp(sign){
    const N=600, out=[]; let cur=[];
    for(let i=0;i<=N;i++){
      const x=xmin+(xmax-xmin)*i/N;
      const v=x*x*x + a*x + b;
      if(v<0){ if(cur.length>1) out.push(cur); cur=[]; continue; }
      const y=sign*Math.sqrt(v);
      if(y<ymin||y>ymax){ if(cur.length>1) out.push(cur); cur=[]; continue; }
      cur.push(toPx(x,y));
    }
    if(cur.length>1) out.push(cur);
    return out;
  }
  const all = [...samp(+1), ...samp(-1)];
  for(const arr of all){
    const d='M'+arr.map(p=>p[0].toFixed(1)+','+p[1].toFixed(1)).join(' L');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--yellow)','stroke-width':2}));
  }

  // sample tracking point, apply the automorphism angle t
  // For Z/2: (x,y) → (x, -y). Linear interp on y.
  // For Z/4 (j=1728): rotate by 90°· t on (x, y) → (-x, iy) complex; we simulate by rotating the DISPLAYED
  //   representative: (x, y) in plane gets rotated: x -> x·cos(πt/2) - y·sin(πt/2) ? No: we want to show a 4-fold symmetry.
  // For demo, draw a ghost (rotated by the group action). We'll just mark the aut by rotating a marker point
  // by the group action around the origin (as a geometric avatar only).
  const order = mode==='generic'?2: mode==='j1728'?4: 6;
  const angle = (2*Math.PI/order) * t;
  const mx = 1.3, my = Math.sqrt(Math.max(0, mx*mx*mx + a*mx + b));
  // rotate (mx,my) by angle (avatar rotation only)
  const rx = mx*Math.cos(angle) - my*Math.sin(angle);
  const ry = mx*Math.sin(angle) + my*Math.cos(angle);
  const [px,py] = toPx(rx, ry);
  svg.appendChild(SVG('circle',{cx:px,cy:py,r:6,fill:'var(--pink)'}));
  const [ox,oy] = toPx(mx,my);
  svg.appendChild(SVG('circle',{cx:ox,cy:oy,r:4,fill:'var(--blue)','fill-opacity':0.5}));

  const lab = SVG('text',{x:X0+10,y:Y0+22,'font-size':14,fill:'var(--mute)'});
  lab.textContent = `mode: ${mode}   j = ${D.j}   Aut = ${D.aut}`;
  svg.appendChild(lab);
  const hint = SVG('text',{x:X0+W-10,y:Y0+22,'font-size':12,fill:'var(--mute)','text-anchor':'end'});
  hint.textContent = `order of Aut: ${order}`;
  svg.appendChild(hint);

  out.textContent = D.desc;
}

