   desc:'dim M₄ = 9. Generic g=4 curve is a complete intersection of quadric + cubic in P³.'},
  {key:'g2n1', g:2, n:0, stable:true, title:'(g,n) = (2,0) · nodal: two elliptic curves glued at a point',
   desc:'Stable degeneration in ∂M̄₂: two genus-1 components meeting at a node. Arithmetic genus = 1+1+0 = 2. ✓ stable: each genus-1 component has 1 special point (the node).'},
  {key:'g2n2', g:2, n:0, stable:true, title:'(g,n) = (2,0) · irreducible self-node',
   desc:'Geometric genus 1, arithmetic genus 2 via the self-node. Smoothing parameter gives a local chart of M̄₂ near the boundary.'},
  {key:'g0n5', g:0, n:5, stable:true, title:'(g,n) = (0,5) · P¹ with 5 marked points',
   desc:'dim M₀,₅ = 2. The boundary ∂M̄₀,₅ is a union of divisors, one for each way to split {1..5} into two groups of size ≥ 2.'},
];

let idx = 1;

function drawCurve(key){
  // draw a schematic "curve" in the middle of the SVG
  const W=620, H=340;
  svg.innerHTML = '';
  svg.appendChild(SVG('rect',{x:20,y:20,width:W-40,height:H-40,fill:'var(--panel2)',stroke:'var(--line)'}));

  // For each key, hand-crafted cartoon
  function genus0(cx,cy){
    // a horizontal line with 3 or 5 dots
    svg.appendChild(SVG('line',{x1:cx-140,y1:cy,x2:cx+140,y2:cy,stroke:'var(--yellow)','stroke-width':2}));
    return {cx,cy};
  }
  function genusHandles(cx,cy,n){
    // draw a tube with n handles (figure of genus n via n circles stacked horizontally, connected)
    // For simplicity just draw n circles joined.
    const spacing = 70;
    const x0 = cx - (n-1)*spacing/2;
    for(let i=0;i<n;i++){
      svg.appendChild(SVG('ellipse',{cx:x0+i*spacing,cy:cy,rx:35,ry:24,fill:'none',stroke:'var(--yellow)','stroke-width':2}));
    }
    // connect them with a bold envelope
    const env = SVG('ellipse',{cx:cx,cy:cy,rx:(n-1)*spacing/2+50,ry:36,fill:'none',stroke:'var(--yellow)','stroke-width':1.5,'stroke-dasharray':'3 3'});
    svg.appendChild(env);
  }
  function markDots(cx, cy, count, yOffset=0){
    for(let i=0;i<count;i++){
      const x = cx - (count-1)*20 + i*40;
      svg.appendChild(SVG('circle',{cx:x,cy:cy+yOffset,r:5,fill:'var(--pink)',stroke:'#fff','stroke-width':1}));
      const t = SVG('text',{x:x,y:cy+yOffset-12,'text-anchor':'middle','font-size':11,fill:'var(--pink)'});
      t.textContent = 'p'+(i+1);
      svg.appendChild(t);
    }
  }

  const cx=W/2, cy=H/2-10;
  if(key==='g0'){ genus0(cx,cy); markDots(cx,cy,3,-10); }
  else if(key==='g1'){ genusHandles(cx,cy,1); markDots(cx,cy-40,1); }
  else if(key==='g2'){ genusHandles(cx,cy,2); }
  else if(key==='g3'){ genusHandles(cx,cy,3); }
  else if(key==='g4'){ genusHandles(cx,cy,4); }
  else if(key==='g2n1'){
    // two ellipses meeting at a central node
    svg.appendChild(SVG('ellipse',{cx:cx-70,cy:cy,rx:55,ry:35,fill:'none',stroke:'var(--yellow)','stroke-width':2}));
    svg.appendChild(SVG('ellipse',{cx:cx+70,cy:cy,rx:55,ry:35,fill:'none',stroke:'var(--cyan)','stroke-width':2}));
    svg.appendChild(SVG('circle',{cx:cx,cy:cy,r:5,fill:'var(--pink)'}));
    const t = SVG('text',{x:cx,y:cy+25,'text-anchor':'middle','font-size':12,fill:'var(--pink)'}); t.textContent='node'; svg.appendChild(t);
    const t1 = SVG('text',{x:cx-70,y:cy-50,'text-anchor':'middle','font-size':11,fill:'var(--yellow)'}); t1.textContent='g=1'; svg.appendChild(t1);
    const t2 = SVG('text',{x:cx+70,y:cy-50,'text-anchor':'middle','font-size':11,fill:'var(--cyan)'}); t2.textContent='g=1'; svg.appendChild(t2);
  }
  else if(key==='g2n2'){
    // one curve with a self-node: draw a "figure eight-ish" shape
    svg.appendChild(SVG('path',{d:`M ${cx-80} ${cy} C ${cx-80} ${cy-60}, ${cx+20} ${cy-60}, ${cx+20} ${cy} S ${cx+120} ${cy+60}, ${cx+120} ${cy} C ${cx+120} ${cy-40}, ${cx-30} ${cy+60}, ${cx-80} ${cy} Z`,
      fill:'none',stroke:'var(--yellow)','stroke-width':2}));
    svg.appendChild(SVG('circle',{cx:cx+5,cy:cy,r:5,fill:'var(--pink)'}));
    const t = SVG('text',{x:cx+5,y:cy+20,'text-anchor':'middle','font-size':12,fill:'var(--pink)'}); t.textContent='self-node'; svg.appendChild(t);
  }
  else if(key==='g0n5'){
    genus0(cx,cy); markDots(cx,cy,5,-10);
  }

  // caption
  const D = GALLERY.find(g=>g.key===key);
  const title = SVG('text',{x:cx,y:40,'text-anchor':'middle','font-size':14,fill:'#fff','font-weight':600});
  title.textContent = D.title;
  svg.appendChild(title);

  // dimension formula
  let dim;
  if(D.g === 0) dim = Math.max(0, D.n - 3);
  else if(D.g === 1) dim = D.n;
  else dim = 3*D.g - 3 + D.n;
  const dimT = SVG('text',{x:cx,y:H-35,'text-anchor':'middle','font-size':13,fill:'var(--yellow)'});
  dimT.textContent = `dim M_{${D.g},${D.n}} = ${dim}   (g=${D.g}, n=${D.n})`;
  svg.appendChild(dimT);

  out.textContent = D.desc + (D.stable ? '   [stable ✓]' : '   [NOT stable]');
}

// build buttons
GALLERY.forEach((g, i) => {
  const b = document.createElement('button');
  b.textContent = `(g=${g.g}, n=${g.n})${g.key.includes('n1')||g.key.includes('n2')?' nodal':''}`;
  b.addEventListener('click', () => {
    idx = i;
    [...row.querySelectorAll('button')].forEach(x=>x.classList.remove('active'));
    b.classList.add('active');
    drawCurve(g.key);
  });
  if(i===idx) b.classList.add('active');
  row.appendChild(b);
});

drawCurve(GALLERY[idx].key);
